Bash(bun x tsx <<'EOF'
import { connect } from "@/client.js";

const client = await connect\("http://localhost:9222"\);
const page = await client.page\("agritech-login"\);

// Get the ARIA snapshot to see if there's an error message
const snapshot = await client.getAISnapshot\("agritech-login"\);
console.log\("=== PAGE SNAPSHOT \(looking for errors\) ==="\);
console.log\(snapshot\);

// Also check browser console for errors
const pageErrors = await page.evaluate\(\(\) => {
  return \(window as any\).lastError || "No error captured";
}\);
console.log\("\\n=== BROWSER CONTEXT ERRORS ==="\);
console.log\(pageErrors\);

await client.disconnect\(\);
EOF)
